     1→import { EventEmitter } from 'node:events';
     2→import { mkdirSync } from 'node:fs';
     3→import { join, resolve } from 'node:path';
     4→import { homedir } from 'node:os';
     5→import { writeFileSync } from 'node:fs';
     6→import type { ServerConfig } from '../config/types.js';
     7→import type { TaskRecord, TaskStatus } from '../state/types.js';
     8→import type { ClaudeEvent, ExecutionResult, TaskInput } from '../claude/types.js';
     9→import { StateStore } from '../state/store.js';
    10→import { transition } from './state-machine.js';
    11→import { buildPrompt } from '../claude/prompt-builder.js';
    12→import { executeClaudeCode } from '../claude/executor.js';
    13→import { commitAndPush } from '../git/branch.js';
    14→import { createWorktree, removeWorktree, findGitRepo } from '../git/worktree.js';
    15→import { branchName } from '../git/branch.js';
    16→
    17→export class PipelineManager extends EventEmitter {
    18→  private store: StateStore;
    19→  private config: ServerConfig;
    20→  private activeCount = 0;
    21→  private queue: string[] = [];
    22→  private processing = false;
    23→
    24→  constructor(store: StateStore, config: ServerConfig) {
    25→    super();
    26→    this.store = store;
    27→    this.config = config;
    28→  }
    29→
    30→  submitTask(input: TaskInput): TaskRecord {
    31→    const existing = this.store.getTask(input.key);
    32→    if (existing && (existing.status === 'queued' || existing.status === 'in-progress')) {
    33→      throw new Error(`Task ${input.key} is already ${existing.status}`);
    34→    }
    35→
    36→    const task: TaskRecord = {
    37→      key: input.key,
    38→      summary: input.summary,
    39→      description: input.description,
    40→      acceptanceCriteria: input.acceptanceCriteria,
    41→      priority: input.priority,
    42→      issueType: input.issueType,
    43→      labels: input.labels,
    44→      comments: input.comments,
    45→      subtasks: input.subtasks,
    46→      linkedIssues: input.linkedIssues,
    47→      attachments: input.attachments,
    48→      assignee: input.assignee,
    49→      reporter: input.reporter,
    50→      components: input.components,
    51→      parentKey: input.parentKey,
    52→      jiraUrl: input.jiraUrl,
    53→      status: 'queued',
    54→      // Preserve branch name from previous attempt so we continue on the same branch
    55→      branchName: existing?.branchName,
    56→      createdAt: new Date().toISOString(),
    57→      updatedAt: new Date().toISOString(),
    58→    };
    59→
    60→    this.store.upsertTask(task);
    61→    this.store.flushSync();
    62→    this.queue.push(task.key);
    63→    this.emit('task-created', task);
    64→    setImmediate(() => this.processQueue());
    65→    return task;
    66→  }
    67→
    68→  retryTask(key: string): TaskRecord {
    69→    const task = this.store.getTask(key);
    70→    if (!task) throw new Error(`Task ${key} not found`);
    71→
    72→    const newStatus = transition(task.status, 'retry');
    73→    const oldStatus = task.status;
    74→    this.store.updateTaskStatus(key, newStatus, { errorMessage: undefined });
    75→    this.store.flushSync();
    76→    this.queue.push(key);
    77→    this.emit('task-status-changed', this.store.getTask(key)!, oldStatus);
    78→    setImmediate(() => this.processQueue());
    79→    return this.store.getTask(key)!;
    80→  }
    81→
    82→  private processQueue(): void {
    83→    if (this.processing) return;
    84→    this.processing = true;
    85→
    86→    try {
    87→      while (this.queue.length > 0 && this.activeCount < this.config.pipeline.concurrency) {
    88→        const key = this.queue.shift();
    89→        if (!key) break;
    90→        const task = this.store.getTask(key);
    91→        if (!task) continue;
    92→        this.runTask(key);
    93→      }
    94→    } finally {
    95→      this.processing = false;
    96→    }
    97→  }
    98→
    99→  private transitionTask(key: string, action: 'start' | 'complete' | 'fail', extra?: Partial<TaskRecord>): void {
   100→    const task = this.store.getTask(key);
   101→    if (!task) return;
   102→    const oldStatus = task.status;
   103→    const newStatus = transition(task.status, action);
   104→    this.store.updateTaskStatus(key, newStatus, extra);
   105→    this.store.flushSync();
   106→    const updated = this.store.getTask(key)!;
   107→    this.emit('task-status-changed', updated, oldStatus);
   108→    if (newStatus === 'completed' || newStatus === 'failed') {
   109→      this.emit('task-completed', updated);
   110→    }
   111→  }
   112→
   113→  private async runTask(key: string): Promise<void> {
   114→    const task = this.store.getTask(key)!;
   115→    const repoRoot = this.config.repoPath;
   116→
   117→    this.activeCount++;
   118→    console.log(`\n${'='.repeat(60)}`);
   119→    console.log(`[PIPELINE] Starting task: ${task.key} — ${task.summary} (${this.activeCount}/${this.config.pipeline.concurrency} active)`);
   120→    console.log(`[PIPELINE] Repo root: ${repoRoot}`);
   121→    console.log(`${'='.repeat(60)}`);
   122→    this.transitionTask(key, 'start', { startedAt: new Date().toISOString() });
   123→
   124→    const logsDir = this.config.logsDir ?? resolve(homedir(), '.jiranimo', 'logs');
   125→    mkdirSync(logsDir, { recursive: true });
   126→    const logPath = join(logsDir, `${key}-${Date.now()}.jsonl`);
   127→    const logLines: string[] = [];
   128→    let worktreePath: string | null = null;
   129→    let gitRepoPath: string | null = null;
   130→
   131→    try {
   132→      // 1. Find the git repo inside repoRoot
   133→      gitRepoPath = await findGitRepo(repoRoot);
   134→      if (!gitRepoPath) {
   135→        throw new Error(`No git repository found in ${repoRoot}`);
   136→      }
   137→      console.log(`[PIPELINE] Git repo: ${gitRepoPath}`);
   138→
   139→      // 2. Create a worktree for this task (isolated from user's working directory)
   140→      // Reuse existing branch name if this is a re-implementation, otherwise generate a new one
   141→      const branch = task.branchName ?? branchName(this.config.git.branchPrefix, task.key, task.summary);
   142→      worktreePath = await createWorktree(
   143→        gitRepoPath,
   144→        task.key,
   145→        branch,
   146→        this.config.git.defaultBaseBranch,
   147→        this.config.git.pushRemote,
   148→      );
   149→      console.log(`[PIPELINE] Worktree created: ${worktreePath}`);
   150→      console.log(`[PIPELINE] Branch: ${branch}`);
   151→      this.store.updateTaskStatus(key, 'in-progress', { branchName: branch });
   152→
   153→      // 3. Build prompt and run Claude in the worktree
   154→      const prompt = buildPrompt(task, this.config.claude.appendSystemPrompt);
   155→
   156→      console.log(`[PIPELINE] Prompt built (${prompt.length} chars)`);
   157→      console.log(`[PIPELINE] Spawning Claude Code in worktree...`);
   158→      console.log(`${'─'.repeat(60)}`);
   159→
   160→      const result: ExecutionResult = await executeClaudeCode({
   161→        prompt,
   162→        cwd: worktreePath,
   163→        config: this.config.claude,
   164→        timeoutMs: 30 * 60 * 1000,
   165→        onEvent: (event: ClaudeEvent) => {
   166→          logLines.push(JSON.stringify(event.raw));
   167→          this.emit('task-output', key, JSON.stringify(event.raw));
   168→          if (event.text) {
   169→            console.log(`[CLAUDE] ${event.text}`);
   170→          } else if (event.type === 'init' && event.sessionId) {
   171→            console.log(`[CLAUDE] Session started: ${event.sessionId}`);
   172→          } else if (event.type === 'result') {
   173→            console.log(`[CLAUDE] Result: ${event.isError ? 'ERROR' : 'SUCCESS'} — ${event.text?.slice(0, 200) || ''}`);
   174→          }
   175→        },
   176→        onOutput: (raw: string) => {
   177→          for (const line of raw.split('\n')) {
   178→            const trimmed = line.trim();
   179→            if (trimmed && !trimmed.startsWith('{')) {
   180→              console.log(`[CLAUDE RAW] ${trimmed}`);
   181→            }
   182→          }
   183→        },
   184→      });
   185→
   186→      console.log(`${'─'.repeat(60)}`);
   187→      console.log(`[PIPELINE] Claude finished — success: ${result.success}, cost: $${result.costUsd ?? 0}, duration: ${result.durationMs}ms`);
   188→      writeFileSync(logPath, logLines.join('\n'), 'utf-8');
   189→      console.log(`[PIPELINE] Logs saved to: ${logPath}`);
   190→
   191→      if (!result.success) {
   192→        throw new Error(result.resultText);
   193→      }
   194→
   195→      // 4. Commit and push from the worktree
   196→      await commitAndPush(
   197→        worktreePath,
   198→        branch,
   199→        task.key,
   200→        task.summary,
   201→        task.issueType,
   202→        task.jiraUrl,
   203→        this.config.git.pushRemote,
   204→      );
   205→      console.log(`[PIPELINE] Changes committed and pushed`);
   206→
   207→      this.transitionTask(key, 'complete', {
   208→        claudeSessionId: result.sessionId,
   209→        claudeCostUsd: result.costUsd,
   210→        claudeResultText: result.resultText,
   211→        logPath,
   212→        completedAt: new Date().toISOString(),
   213→      });
   214→      console.log(`[PIPELINE] ✓ Task ${key} completed successfully`);
   215→      console.log(`${'='.repeat(60)}\n`);
   216→    } catch (err) {
   217→      writeFileSync(logPath, logLines.join('\n'), 'utf-8');
   218→      console.error(`[PIPELINE] ✗ Task ${key} failed: ${(err as Error).message}`);
   219→      console.log(`[PIPELINE] Logs: ${logPath}`);
   220→      console.log(`${'='.repeat(60)}\n`);
   221→      this.transitionTask(key, 'fail', {
   222→        errorMessage: (err as Error).message,
   223→        logPath,
   224→      });
   225→    } finally {
   226→      // 5. Clean up worktree
   227→      if (worktreePath && gitRepoPath) {
   228→        try {
   229→          await removeWorktree(gitRepoPath, worktreePath);
   230→          console.log(`[PIPELINE] Worktree removed: ${worktreePath}`);
   231→        } catch (err) {
   232→          console.warn(`[PIPELINE] Failed to remove worktree: ${(err as Error).message}`);
   233→        }
   234→      }
   235→      this.activeCount--;
   236→      this.processQueue();
   237→    }
   238→  }
   239→}
