     1→import type { TaskStatus } from '../state/types.js';
     2→import type { TaskAction } from './types.js';
     3→
     4→const transitions: Record<string, TaskStatus> = {
     5→  'queued:start': 'in-progress',
     6→  'queued:fail': 'failed',
     7→  'in-progress:complete': 'completed',
     8→  'in-progress:fail': 'failed',
     9→  'failed:retry': 'queued',
    10→};
    11→
    12→export function transition(currentStatus: TaskStatus, action: TaskAction): TaskStatus {
    13→  const key = `${currentStatus}:${action}`;
    14→  const next = transitions[key];
    15→  if (!next) {
    16→    throw new Error(`Invalid transition: cannot apply "${action}" to task in "${currentStatus}" status`);
    17→  }
    18→  return next;
    19→}
