     1→import { execFile } from 'node:child_process';
     2→import { promisify } from 'node:util';
     3→import type { PrResult } from './types.js';
     4→
     5→const exec = promisify(execFile);
     6→
     7→export interface CreatePrOptions {
     8→  cwd: string;
     9→  baseBranch: string;
    10→  headBranch: string;
    11→  title: string;
    12→  body: string;
    13→  githubRepo?: string;
    14→  draft?: boolean;
    15→}
    16→
    17→export async function createDraftPr(options: CreatePrOptions): Promise<PrResult> {
    18→  const args = [
    19→    'pr', 'create',
    20→    '--title', options.title,
    21→    '--body', options.body,
    22→    '--base', options.baseBranch,
    23→    '--head', options.headBranch,
    24→  ];
    25→
    26→  if (options.draft !== false) {
    27→    args.push('--draft');
    28→  }
    29→
    30→  if (options.githubRepo) {
    31→    args.push('--repo', options.githubRepo);
    32→  }
    33→
    34→  const { stdout } = await exec('gh', args, { cwd: options.cwd });
    35→  const url = stdout.trim();
    36→
    37→  // Extract PR number from URL (e.g., https://github.com/owner/repo/pull/42)
    38→  const match = url.match(/\/pull\/(\d+)/);
    39→  const number = match ? parseInt(match[1], 10) : 0;
    40→
    41→  return { url, number };
    42→}
    43→
    44→export function buildPrTitle(issueKey: string, summary: string): string {
    45→  return `[${issueKey}] ${summary}`;
    46→}
    47→
    48→export function buildPrBody(options: {
    49→  issueKey: string;
    50→  summary: string;
    51→  description: string;
    52→  jiraUrl: string;
    53→  resultText: string;
    54→  costUsd?: number;
    55→  durationMs?: number;
    56→}): string {
    57→  const lines: string[] = [
    58→    `## Summary`,
    59→    `Automated implementation of [${options.issueKey}](${options.jiraUrl}): ${options.summary}`,
    60→    '',
    61→    `## Description`,
    62→    options.description.slice(0, 500),
    63→    '',
    64→    `## Implementation Notes`,
    65→    options.resultText.slice(0, 1000),
    66→    '',
    67→    `## Metadata`,
    68→    `- Jira Task: [${options.issueKey}](${options.jiraUrl})`,
    69→    `- Generated by: Jiranimo + Claude Code`,
    70→  ];
    71→
    72→  if (options.costUsd !== undefined) {
    73→    lines.push(`- Cost: $${options.costUsd.toFixed(2)}`);
    74→  }
    75→  if (options.durationMs !== undefined) {
    76→    const secs = Math.round(options.durationMs / 1000);
    77→    const mins = Math.floor(secs / 60);
    78→    const remainSecs = secs % 60;
    79→    lines.push(`- Duration: ${mins}m ${remainSecs}s`);
    80→  }
    81→
    82→  lines.push('', '---', '> This PR was automatically generated by Jiranimo. Please review carefully before merging.');
    83→
    84→  return lines.join('\n');
    85→}
