    81→/**
    82→ * Remove a worktree and its branch.
    83→ */
    84→export async function removeWorktree(repoPath: string, worktreePath: string): Promise<void> {
    85→  try {
    86→    await git(['worktree', 'remove', worktreePath, '--force'], repoPath);
    87→  } catch {
    88→    // If remove fails, try pruning
    89→    await git(['worktree', 'prune'], repoPath).catch(() => {});
    90→  }
    91→}
