    93→/**
    94→ * Clean up stale worktree entries (e.g., after crashes).
    95→ * Call on server startup.
    96→ */
    97→export async function pruneWorktrees(repoPath: string): Promise<void> {
    98→  await git(['worktree', 'prune'], repoPath).catch(() => {});
