   101→/**
   102→ * Find the first git repository inside a directory.
   103→ * A directory is a git repo if it contains a `.git` directory (not just being inside one).
   104→ */
   105→export async function findGitRepo(rootPath: string): Promise<string | null> {
   106→  // Check if rootPath itself has a .git directory
   107→  if (existsSync(join(rootPath, '.git'))) {
   108→    return rootPath;
   109→  }
   110→
   111→  // Scan subdirectories for a .git directory
   112→  const { readdirSync } = await import('node:fs');
   113→  for (const entry of readdirSync(rootPath, { withFileTypes: true })) {
   114→    if (!entry.isDirectory() || entry.name.startsWith('.')) continue;
   115→    const subPath = join(rootPath, entry.name);
   116→    if (existsSync(join(subPath, '.git'))) {
   117→      return subPath;
   118→    }
   119→  }
   120→
   121→  return null;
   122→}
