     1→import { spawn, type ChildProcess } from 'node:child_process';
     2→import { OutputParser } from './output-parser.js';
     3→import type { ClaudeConfig } from '../config/types.js';
     4→import type { ExecutionResult, ClaudeEvent } from './types.js';
     5→
     6→export interface ExecutorOptions {
     7→  prompt: string;
     8→  cwd: string;
     9→  config: ClaudeConfig;
    10→  timeoutMs?: number;
    11→  env?: Record<string, string>;
    12→  onEvent?: (event: ClaudeEvent) => void;
    13→  onOutput?: (line: string) => void;
    14→}
    15→
    16→export async function executeClaudeCode(options: ExecutorOptions): Promise<ExecutionResult> {
    17→  const { prompt, cwd, config, timeoutMs = 30 * 60 * 1000, onEvent, onOutput } = options;
    18→  const startTime = Date.now();
    19→
    20→  const commandStr = config.command ?? 'claude';
    21→  // Split command string into program + pre-args (e.g. "node /path/to/script.mjs" → ["node", "/path/to/script.mjs"])
    22→  const commandParts = commandStr.split(/\s+/);
    23→  const program = commandParts[0];
    24→  const preArgs = commandParts.slice(1);
    25→  const args = [...preArgs, ...buildArgs(prompt, config)];
    26→
    27→  return new Promise<ExecutionResult>((resolve, reject) => {
    28→    const child: ChildProcess = spawn(program, args, {
    29→      cwd,
    30→      env: { ...process.env, ...options.env },
    31→      stdio: ['ignore', 'pipe', 'pipe'],
    32→    });
    33→
    34→    const parser = new OutputParser();
    35→    let resultEvent: ClaudeEvent | null = null;
    36→    let stderr = '';
    37→
    38→    parser.on('event', (event: ClaudeEvent) => {
    39→      onEvent?.(event);
    40→    });
    41→
    42→    parser.on('result', (event: ClaudeEvent) => {
    43→      resultEvent = event;
    44→    });
    45→
    46→    child.stdout?.on('data', (chunk: Buffer) => {
    47→      const text = chunk.toString();
    48→      onOutput?.(text);
    49→      parser.feed(text);
    50→    });
    51→
    52→    child.stderr?.on('data', (chunk: Buffer) => {
    53→      stderr += chunk.toString();
    54→    });
    55→
    56→    // Timeout handling
    57→    const timer = setTimeout(() => {
    58→      child.kill('SIGTERM');
    59→      setTimeout(() => {
    60→        if (!child.killed) child.kill('SIGKILL');
    61→      }, 10_000);
    62→    }, timeoutMs);
    63→
    64→    child.on('close', (code) => {
    65→      clearTimeout(timer);
    66→      parser.flush();
    67→      const durationMs = Date.now() - startTime;
    68→
    69→      if (resultEvent) {
    70→        resolve({
    71→          success: !resultEvent.isError && code === 0,
    72→          resultText: resultEvent.text ?? '',
    73→          sessionId: resultEvent.sessionId,
    74→          costUsd: resultEvent.costUsd,
    75→          durationMs,
    76→        });
    77→      } else {
    78→        resolve({
    79→          success: false,
    80→          resultText: stderr || `Process exited with code ${code}`,
    81→          durationMs,
    82→        });
    83→      }
    84→    });
    85→
    86→    child.on('error', (err) => {
    87→      clearTimeout(timer);
    88→      reject(new Error(`Failed to spawn Claude Code: ${err.message}`));
    89→    });
    90→  });
    91→}
    92→
    93→function buildArgs(prompt: string, config: ClaudeConfig): string[] {
    94→  const args: string[] = [
    95→    '-p', prompt,
    96→    '--output-format', 'stream-json',
    97→    '--verbose',
    98→    '--dangerously-skip-permissions',
    99→  ];
   100→
   101→  if (config.model) {
   102→    args.push('--model', config.model);
   103→  }
   104→  if (config.maxBudgetUsd) {
   105→    args.push('--max-budget-usd', String(config.maxBudgetUsd));
   106→  }
   107→  if (config.appendSystemPrompt) {
   108→    args.push('--append-system-prompt', config.appendSystemPrompt);
   109→  }
   110→  if (config.effortLevel) {
   111→    args.push('--effort', config.effortLevel);
   112→  }
   113→
   114→  return args;
   115→}
