     1→import type { TaskInput } from './types.js';
     2→
     3→const MAX_DESCRIPTION_LENGTH = 10_000;
     4→const MAX_COMMENTS = 10;
     5→
     6→export function buildPrompt(task: TaskInput, appendPrompt?: string): string {
     7→  const sections: string[] = [];
     8→
     9→  sections.push(`You are implementing a Jira task. You are in a git repository on a dedicated feature branch. Implement the changes described below.`);
    10→  sections.push(`## Task: ${task.key} - ${task.summary}`);
    11→
    12→  // Description
    13→  let description = task.description || 'No description provided.';
    14→  if (description.length > MAX_DESCRIPTION_LENGTH) {
    15→    description = description.slice(0, MAX_DESCRIPTION_LENGTH) + '\n\n... (description truncated)';
    16→  }
    17→  sections.push(`### Description\n${description}`);
    18→
    19→  // Acceptance criteria
    20→  if (task.acceptanceCriteria) {
    21→    sections.push(`### Acceptance Criteria\n${task.acceptanceCriteria}`);
    22→  }
    23→
    24→  // Subtasks
    25→  if (task.subtasks && task.subtasks.length > 0) {
    26→    const lines = task.subtasks.map(s => `- [${s.status === 'Done' ? 'x' : ' '}] ${s.key}: ${s.summary} (${s.status})`);
    27→    sections.push(`### Subtasks\n${lines.join('\n')}`);
    28→  }
    29→
    30→  // Linked issues
    31→  if (task.linkedIssues && task.linkedIssues.length > 0) {
    32→    const lines = task.linkedIssues.map(l => `- ${l.type}: ${l.key} — ${l.summary} (${l.status})`);
    33→    sections.push(`### Linked Issues\n${lines.join('\n')}`);
    34→  }
    35→
    36→  // Parent issue
    37→  if (task.parentKey) {
    38→    sections.push(`### Parent Issue\n${task.parentKey}`);
    39→  }
    40→
    41→  // Comments
    42→  if (task.comments.length > 0) {
    43→    const recent = task.comments.slice(-MAX_COMMENTS);
    44→    const commentLines = recent.map(c => {
    45→      const date = c.created ? ` (${new Date(c.created).toLocaleDateString()})` : '';
    46→      return `**${c.author}**${date}: ${c.body}`;
    47→    }).join('\n\n');
    48→    sections.push(`### Recent Comments\n${commentLines}`);
    49→  }
    50→
    51→  // Attachments
    52→  if (task.attachments && task.attachments.length > 0) {
    53→    const lines = task.attachments.map(a => `- ${a.filename} (${a.mimeType})`);
    54→    sections.push(`### Attachments\n${lines.join('\n')}`);
    55→  }
    56→
    57→  // Metadata
    58→  const metaLines = [
    59→    `- Priority: ${task.priority}`,
    60→    `- Type: ${task.issueType}`,
    61→    `- Labels: ${task.labels.join(', ') || 'none'}`,
    62→  ];
    63→  if (task.assignee) metaLines.push(`- Assignee: ${task.assignee}`);
    64→  if (task.reporter) metaLines.push(`- Reporter: ${task.reporter}`);
    65→  if (task.components && task.components.length > 0) metaLines.push(`- Components: ${task.components.join(', ')}`);
    66→  metaLines.push(`- Jira: ${task.jiraUrl}`);
    67→  sections.push(`### Metadata\n${metaLines.join('\n')}`);
    68→
    69→  // Instructions
    70→  sections.push(`### Instructions
    71→1. Read the codebase to understand the existing architecture, patterns, and conventions.
    72→2. Implement the changes described above, following existing code style.
    73→3. Write or update tests as appropriate.
    74→4. Ensure the code compiles and lints cleanly.
    75→5. Do NOT run git commands — the orchestrating system handles branching, committing, and pushing.`);
    76→
    77→  if (appendPrompt) {
    78→    sections.push(appendPrompt);
    79→  }
    80→
    81→  return sections.join('\n\n');
    82→}
