     1→import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';
     2→import { dirname } from 'node:path';
     3→import { homedir } from 'node:os';
     4→import { resolve } from 'node:path';
     5→import type { AppState, TaskRecord, TaskStatus } from './types.js';
     6→
     7→const DEFAULT_STATE_PATH = resolve(homedir(), '.jiranimo', 'state.json');
     8→
     9→function emptyState(): AppState {
    10→  return { tasks: {} };
    11→}
    12→
    13→export class StateStore {
    14→  private state: AppState;
    15→  private filePath: string;
    16→  private flushTimer: ReturnType<typeof setTimeout> | null = null;
    17→  private flushDelayMs: number;
    18→
    19→  constructor(options?: { filePath?: string; flushDelayMs?: number }) {
    20→    this.filePath = options?.filePath ?? DEFAULT_STATE_PATH;
    21→    this.flushDelayMs = options?.flushDelayMs ?? 100;
    22→    this.state = this.load();
    23→  }
    24→
    25→  private load(): AppState {
    26→    try {
    27→      const raw = readFileSync(this.filePath, 'utf-8');
    28→      const parsed = JSON.parse(raw);
    29→      if (parsed && typeof parsed === 'object' && parsed.tasks) {
    30→        return parsed as AppState;
    31→      }
    32→      return emptyState();
    33→    } catch {
    34→      return emptyState();
    35→    }
    36→  }
    37→
    38→  private scheduleFlush(): void {
    39→    if (this.flushTimer) return;
    40→    this.flushTimer = setTimeout(() => {
    41→      this.flushSync();
    42→      this.flushTimer = null;
    43→    }, this.flushDelayMs);
    44→  }
    45→
    46→  flushSync(): void {
    47→    if (this.flushTimer) {
    48→      clearTimeout(this.flushTimer);
    49→      this.flushTimer = null;
    50→    }
    51→    mkdirSync(dirname(this.filePath), { recursive: true });
    52→    writeFileSync(this.filePath, JSON.stringify(this.state, null, 2), 'utf-8');
    53→  }
    54→
    55→  getTask(key: string): TaskRecord | undefined {
    56→    return this.state.tasks[key];
    57→  }
    58→
    59→  getAllTasks(): TaskRecord[] {
    60→    return Object.values(this.state.tasks);
    61→  }
    62→
    63→  getTasksByStatus(status: TaskStatus): TaskRecord[] {
    64→    return this.getAllTasks().filter(t => t.status === status);
    65→  }
    66→
    67→  upsertTask(task: TaskRecord): void {
    68→    task.updatedAt = new Date().toISOString();
    69→    this.state.tasks[task.key] = task;
    70→    this.scheduleFlush();
    71→  }
    72→
    73→  updateTaskStatus(key: string, status: TaskStatus, extra?: Partial<TaskRecord>): TaskRecord {
    74→    const task = this.state.tasks[key];
    75→    if (!task) throw new Error(`Task ${key} not found`);
    76→    task.status = status;
    77→    task.updatedAt = new Date().toISOString();
    78→    if (extra) Object.assign(task, extra);
    79→    this.scheduleFlush();
    80→    return task;
    81→  }
    82→
    83→  deleteTask(key: string): boolean {
    84→    if (!this.state.tasks[key]) return false;
    85→    delete this.state.tasks[key];
    86→    this.scheduleFlush();
    87→    return true;
    88→  }
    89→
    90→  clear(): void {
    91→    this.state = emptyState();
    92→    this.scheduleFlush();
    93→  }
    94→
    95→  destroy(): void {
    96→    if (this.flushTimer) {
    97→      clearTimeout(this.flushTimer);
    98→      this.flushTimer = null;
    99→    }
   100→  }
   101→}
