    29→// --- Dev mode auto-reload ---
    30→// Connect to server WebSocket and listen for extension-reload signals.
    31→// In production the server isn't on localhost, so this silently fails.
    32→function connectForAutoReload() {
    33→  const wsUrl = serverUrl.replace(/^http/, 'ws') + '/ws';
    34→  try {
    35→    const ws = new WebSocket(wsUrl);
    36→
    37→    ws.onmessage = (event) => {
    38→      try {
    39→        const msg = JSON.parse(event.data);
    40→        if (msg.type === 'extension-reload') {
    41→          console.log(LOG, 'Reload signal received — reloading extension');
    42→          chrome.runtime.reload();
    43→        }
    44→      } catch {
    45→        // ignore
    46→      }
    47→    };
    48→
    49→    ws.onclose = () => {
    50→      // Reconnect after delay (server might restart during dev)
    51→      setTimeout(connectForAutoReload, 5000);
