   291→  /** Simple recursive ADF text extractor */
   292→  function extractTextFromAdf(node) {
   293→    if (!node) return '';
   294→    if (node.type === 'text') return node.text || '';
   295→    if (node.type === 'hardBreak') return '\n';
   296→    if (Array.isArray(node.content)) return node.content.map(extractTextFromAdf).join('');
   297→    if (node.type === 'doc' && Array.isArray(node.content)) return node.content.map(extractTextFromAdf).join('\n\n');
   298→    return '';
   299→  }
